import React from "react";
import "./Home.css";

function Home() {
  return (
    <div className="home-container">
      <h1>Bienvenue sur notre galerie d'art</h1>
      <p className="home-speech">
        Découvrez les œuvres d'artistes talentueux en situation de handicap psychique à Grenoble.  
        Nous leur offrons une plateforme pour exposer et vendre leurs créations : peintures, dessins, sculptures et écrits.  
        Rejoignez-nous pour célébrer la diversité et encourager ces talents incroyables.  
      </p>
    </div>
  );
}

export default Home;
